CustomField.formula:
( IF( Previous_Payment_Amount__c > 0, Previous_Payment_Amount__c, Payment_Amount__c) * 
IF(Previous_Number_of_Payments__c > 0 , Previous_Number_of_Payments__c , Number_of_Payments__c )
)  + IF(Previous_Bulk_Payment_Amount__c > 0, Previous_Bulk_Payment_Amount__c, Bulk_Payment_Amount__c)
